import React, { useState, useMemo } from 'react';
import { useApp } from '../contexts/AppContext';
import { Pencil, Trash2, ChevronUp, ChevronDown } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export default function Produtos() {
  const { produtos, deleteProduto, loading } = useApp();
  const [busca, setBusca] = useState('');
  const [sortConfig, setSortConfig] = useState({ key: 'nome', direction: 'asc' });
  const navigate = useNavigate();

  // Lógica de Filtro
  const produtosFiltrados = useMemo(() => {
    let result = produtos.filter(p => 
      p.nome?.toLowerCase().includes(busca.toLowerCase()) || 
      p.grupo?.toLowerCase().includes(busca.toLowerCase())
    );

    // Lógica de Ordenação
    if (sortConfig.key) {
      result.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) return sortConfig.direction === 'asc' ? -1 : 1;
        if (a[sortConfig.key] > b[sortConfig.key]) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
    return result;
  }, [produtos, busca, sortConfig]);

  const handleSort = (key) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  if (loading) return <div className="mt-24 text-center">Carregando...</div>;

  return (
    <main className="mt-24 container mx-auto p-4">
      <div className="mb-6 flex justify-between items-center">
        <h2 className="text-2xl font-bold">Produtos Cadastrados</h2>
        <input 
          type="text" 
          placeholder="Filtrar por nome ou grupo..." 
          className="border p-2 rounded w-1/3 shadow-sm focus:ring-2 focus:ring-blue-500 outline-none"
          onChange={(e) => setBusca(e.target.value)}
        />
      </div>

      <div className="overflow-x-auto bg-white rounded-lg shadow">
        <table className="w-full text-left border-collapse">
          <thead className="bg-slate-100 border-b">
            <tr>
              {['nome', 'grupo', 'preco_venda', 'quantidade_estoque'].map(col => (
                <th key={col} className="p-4 cursor-pointer hover:bg-slate-200 uppercase text-xs font-semibold" onClick={() => handleSort(col)}>
                  <div className="flex items-center gap-1">
                    {col.replace('_', ' ')}
                    {sortConfig.key === col ? (sortConfig.direction === 'asc' ? <ChevronUp size={14}/> : <ChevronDown size={14}/>) : null}
                  </div>
                </th>
              ))}
              <th className="p-4">Ações</th>
            </tr>
          </thead>
          <tbody>
            {produtosFiltrados.map(prod => (
              <tr key={prod.id} className="border-b hover:bg-slate-50 transition">
                <td className="p-4">{prod.nome}</td>
                <td className="p-4">{prod.grupo}</td>
                <td className="p-4">R$ {prod.preco_venda?.toFixed(2)}</td>
                <td className="p-4">{prod.quantidade_estoque}</td>
                <td className="p-4 flex gap-3">
                  <button onClick={() => navigate(`/cadastro`, { state: { item: prod } })} className="text-blue-600 hover:text-blue-800">
                    <Pencil size={18}/>
                  </button>
                  <button onClick={() => deleteProduto(prod.id)} className="text-red-600 hover:text-red-800">
                    <Trash2 size={18}/>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}
